data: {"type":"content_block_delta","index":1,"delta":{"type":"text_delta","text":"# Rust Programming: Performance with Safety\n\nRust is a systems programming language that has gained significant attention for its unique"}}

event: content_block_delta
data: {"type":"content_block_delta","index":1,"delta":{"type":"text_delta","text":" ability to deliver high performance while eliminating many common programming errors. First released in 2010 by"}}

event: content_block_delta
data: {"type":"content_block_delta","index":1,"delta":{"type":"text_delta","text":" Graydon Hoare at Mozilla, Rust has grown to become one of the most loved programming languages according to developer surveys.\n\n## Memory Safety Without Gar"}}

